(function () {
  const q = document.getElementById(&#039;lib-q&#039;);
  const tree = document.getElementById(&#039;lib-tree&#039;);
  if (!q || !tree) return;

  function nameOf(li) {
    const el = li.querySelector(&#039;:scope &gt; a &gt; .name, :scope &gt; details &gt; summary &gt; .name&#039;);
    return (el &amp;&amp; el.textContent || &#039;&#039;).toLowerCase();
  }

  function applyFilter(term) {
    term = term.trim().toLowerCase();
    tree.querySelectorAll(&#039;li&#039;).forEach(li =&gt; li.classList.remove(&#039;hidden&#039;));
    if (!term) {
      tree.querySelectorAll(&#039;details&#039;).forEach(d =&gt; {
        d.open = d.classList.contains(&#039;top&#039;);
      });
      return;
    }
    tree.querySelectorAll(&#039;li.doc&#039;).forEach(li =&gt; {
      if (!nameOf(li).includes(term)) li.classList.add(&#039;hidden&#039;);
    });
    Array.from(tree.querySelectorAll(&#039;li.folder&#039;)).reverse().forEach(li =&gt; {
      const anyVisible = li.querySelector(&#039;li:not(.hidden)&#039;);
      if (!anyVisible &amp;&amp; !nameOf(li).includes(term)) {
        li.classList.add(&#039;hidden&#039;);
      } else {
        const det = li.querySelector(&#039;:scope &gt; details&#039;);
        if (det) det.open = true;
      }
    });
  }

  q.addEventListener(&#039;input&#039;, e =&gt; applyFilter(e.target.value));
})();

web-development/react.content:
React
React is a JavaScript library for building user interfaces.
Overview
React uses a component-based architecture and virtual DOM for efficient updates.
Core Concepts

Components: Reusable UI pieces
Props: Data passed to components
State: Component-managed data
Hooks: Function component features
JSX: JavaScript XML syntax

Basic Example
import { useState } from &#039;react&#039;;

function Counter() {
  const [count, setCount] = useState(0);

  return (
    &lt;div&gt;
      &lt;h1&gt;Count: {count}&lt;/h1&gt;
      &lt;button onClick={() =&gt; setCount(count + 1)}&gt;
        Increment
      &lt;/button&gt;
    &lt;/div&gt;
  );
}

export default Counter;
Common Hooks
// useState - state management
const [value, setValue] = useState(initialValue);

// useEffect - side effects
useEffect(() =&gt; {
  // Effect code
  return () =&gt; {
    // Cleanup
  };
}, [dependencies]);

// useContext - context consumption
const value = useContext(MyContext);

// useRef - mutable reference
const ref = useRef(initialValue);
Best Practices

Keep components small and focused
Use functional components with hooks
Lift state up when needed
Memoize expensive computations
Use keys in lists

web-development/typescript.content:
TypeScript
TypeScript is a typed superset of JavaScript that compiles to plain JavaScript.
Overview
TypeScript adds static typing to JavaScript, catching errors at compile time.
Basic Types
// Primitives
let name: string = &quot;John&quot;;
let age: number = 30;
let isActive: boolean = true;

// Arrays
let numbers: number[] = [1, 2, 3];
let names: Array&lt;string&gt; = [&quot;Alice&quot;, &quot;Bob&quot;];

// Objects
interface User {
  id: number;
  name: string;
  email?: string; // Optional
}

const user: User = {
  id: 1,
  name: &quot;John Doe&quot;
};

// Functions
function greet(name: string): string {
  return `Hello, ${name}!`;
}

// Union types
let value: string | number;
value = &quot;hello&quot;;
value = 42;
Advanced Types
// Generics
function identity&lt;T&gt;(arg: T): T {
  return arg;
}

// Type aliases
type ID = string | number;

// Intersection types
type Admin = User &amp; { role: &quot;admin&quot; };

// Utility types
type PartialUser = Partial&lt;User&gt;;
type ReadonlyUser = Readonly&lt;User&gt;;
Benefits

Early error detection
Better IDE support
Self-documenting code
Safer refactoring
Enhanced team collaboration

backend/api/graphql.content:
GraphQL
GraphQL is a query language for APIs and a runtime for executing queries.
Overview
GraphQL allows clients to request exactly the data they need.
Basic Query
query {
  user(id: &quot;123&quot;) {
    name
    email
    posts {
      title
      createdAt
    }
  }
}
Mutations
mutation {
  createUser(input: {
    name: &quot;John Doe&quot;
    email: &quot;john@example.com&quot;
  }) {
    id
    name
  }
}
Schema Definition
type User {
  id: ID!
  name: String!
  email: String!
  posts: [Post!]!
}

type Post {
  id: ID!
  title: String!
  content: String!
  author: User!
}

type Query {
  user(id: ID!): User
  users: [User!]!
}
Advantages

Request exactly what you need
Single endpoint
Strong typing
Introspection
Real-time with subscriptions

When to Use

Complex data requirements
Mobile apps (reduce bandwidth)
Rapid frontend development
Multiple clients with different needs

